var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하, 하나……! 둘……! 셋!","JPN":"い、いっち…！　にの…！　さんっ！","ENG":"O-one...! Two...! Three...!","TWN":"一……！二……！三！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"영차아!","JPN":"えいっ！","ENG":"Chaa!","TWN":"嘿咻！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"좋아. 우리가 부탁 받은 보급품은 이 컨테이너가 마지막이다.","JPN":"よし。俺たちが頼まれた補給品はこのコンテナで最後だ。","ENG":"All right. This is the last container of supplies we've been asked for.","TWN":"好了。這個貨櫃是我們奉命轉交的最後一件補給品。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아사는 나중에 걱정해도 되겠군. 이걸로 당장 급한 불은 끌 수 있겠어.","JPN":"これでしばらく飢え死ぬ心配はないな。差し迫った問題は解決しそうだ。","ENG":"That's one less thing to worry about for now. Not starving.","TWN":"暫時不用擔心會餓死的問題了。這些東西可以解決我們的燃眉之急。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"프리라이더 아가씨들도 수고했어.","JPN":"フリーライダーのお嬢ちゃんたちもご苦労様。","ENG":"Well done to you as well, Free Riders.","TWN":"免費騎士的二位小姐也辛苦了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"으으, 여기까지 와서도 노동에 시달려야 하다니…….","JPN":"うう、ここに来てまで労働で苦しまないといけないなんて……","ENG":"Ugh, I can’t believe we have to work our butts off in here too...","TWN":"呃呃呃……都到這裡了，居然還要做苦工……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"최첨단 함선에서 사람 손으로 짐을 날라야 하다니……. 너무 가혹한 현실이에요…….","JPN":"最先端の艦船なのに、人力で荷物を運ばなければならないなんて……あまりにも過酷な現実です……","ENG":"Moving supplies by hand in a state-of-the-art ship... It's too sad...","TWN":"在最先進的艦船上，居然還要靠人工來搬運……現實太殘酷了……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"당분간은 참아. 허수공간을 탈출하기 전까진 절약할 수 있는 건 최대한 절약해야 해.","JPN":"しばらくは我慢して。虚数空間を抜け出すまではできるだけ節約しなければいけないわ。","ENG":"Suck it up for now. We have to save everything until we get out of the imaginary space.","TWN":"先忍忍。在逃出虛數空間之前，必須能省則省。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"예를 들어 기중기의 동력이라거나.","JPN":"クレーンの動力とかね。","ENG":"For instance, we should save the power for cranes and stuff.","TWN":"比如起重機的動力什麼的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"으음! 도움이 되지 못해 미안하군!","JPN":"うむ！　役に立てず申し訳ない！","ENG":"Mmh! I'm sorry to be of no help!","TWN":"呃嗯！很抱歉沒能幫上忙！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"할 수 있다면 내 포신에 줄이라도 달고 돕고 싶건만!","JPN":"できるものなら、吾輩の砲身に縄でもひっかけて助けたいところだが！","ENG":"I wish I could connect everything to my gun barrel!","TWN":"如果可以，我想在我的炮身上掛根繩子！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아휴, 정비하다 고막 터지겠는데요! 성량이 너무 커요!","JPN":"もう、整備中に鼓膜が破けちゃいそうなのです！　声が大きすぎなのです！","ENG":"Hey, you're going to blow my ears out! You're too loud!","TWN":"呀，我還在檢修呢！你的音量太大了！耳膜都要炸了啦！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"이러다 늦어지면 손해라니까요! 체르노바 소장님이 데이터 달라고 야단인데!","JPN":"これで遅れが出たらまずいのです！　チェルノワ所長がデータを渡せとうるさいんですから！","ENG":"Things are not going to be pretty if we run late! Director Chernova's waiting for the data!","TWN":"晚，晚了可不行！安娜斯塔莎所長吵著要數據呢！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하, 미안하네! 나 때문에 개장이 늦어지면 안 되지, 아무렴!","JPN":"はは、すまない！　吾輩のせいで改装が遅れては困る、うむ！","ENG":"Ha ha, my apologies! Well, the remodeling shouldn’t be delayed because of me!","TWN":"哈哈，對不起！不能因為我導致改裝推遲，當然！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"제길, 얼른 쫓아가도 모자랄 판국에 이런 데서 한가하게 뭐 하는 거야?","JPN":"クソ、早く追いかけなきゃいけないってときに、こんなところで何をぐずぐずしてんだよ？","ENG":"Damn it, what are we doing? Shouldn’t we be going after them?","TWN":"該死，我們現在是在幹什麼，怎麼還有工夫閒聊啊？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"저 해적 녀석들은 왜 여기 나타난 거고?","JPN":"あの海賊どもは何でここに現れたんだ？","ENG":"And why are those pirates here?","TWN":"話說那群海盜為什麼會出現在這裡？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};